<script>

import gsap from 'gsap'
import p5 from 'p5'

let sketch = (sk) => {    

    var lastPos = {}
    var posArr = []
    const rStep = 40 //Radius Step
    const n = 20 // Amount of Circles
    var noiseFactor = { x: 10 }
    var controlContainer = document.querySelector('#svgContainer')

    sk.setup = () => {
          //console.log(posArr)
      
          sk.createCanvas(controlContainer.clientWidth, controlContainer.clientHeight).parent('svgContainer')
          
          lastPos = {
            x: sk.width / 2,
            y: sk.height / 2
          }
          
          let arrCount = 0

          while (arrCount < n) {
            arrCount++
            posArr.push({
              x: sk.width / 2,
              y: sk.height / 2
            })
          }
          
          //MOVE MOUSE
          let canvas = document.querySelector(".p5Canvas")
          //console.log(canvas)
          
          canvas.addEventListener("pointermove", (e) => {
            //console.log(posArr)
            gsap.to(posArr, {
              x: sk.mouseX,
              y: sk.mouseY,
              stagger: 0.02
            })
            
            gsap.fromTo(noiseFactor, {
              x: 0
            }, {
              x: 10,
              //yoyo: true,
              duration: 0.2
            })
            
          })

          
        
          sk.angleMode(sk.DEGREES)
          sk.colorMode(sk.HSB)
    }

    sk.draw = () => {
        sk.background("#020605") //Background Color
  
  
        let count = n

        while (count > 1) {
          count--
          sk.push()
          sk.translate(posArr[count].x, posArr[count].y)
          createCircle(rStep * count)
          sk.pop()
          //translate(-lastPos.x-5, -lastPos.y-5)
        }

        function createCircle(radius) {
          let bStep = 10
          let bounce = sk.map(sk.cos(sk.mouseX + sk.mouseY)*bStep, -bStep, bStep, 2, 10)
          sk.stroke(260, 60, sk.map(radius, 30, 300, 70, 100))
          sk.fill(264, 85, sk.map(radius, 30, 300, 12, 98))
          sk.beginShape()
          
            for (let i = 0; i < 359; i++) {
              
              let R1 = sk.map(sk.sin(i*radius+sk.frameCount*6), -1, 1, radius-bounce, radius)
              let R2 = sk.map(sk.cos(i*radius/2+sk.frameCount*6), -1, 1, radius-bounce, radius)
              
              let R = R1 + R2

              sk.vertex(R * sk.cos(i), R * sk.sin(i))
            }
          
          sk.endShape(sk.CLOSE)
        }
    }

    sk.windowResized = () => {

    }

}











export default {
  name: 'p3',
  components: {},
  mounted() {

      const P5 = new p5(sketch)

      gsap.to("#light", {
        ease: "none",
        duration: 10,
        rotation: 360,
        repeat: -1,
      })
        
      gsap.to("#lightA", {
        ease: "none",
        duration: 12,
        rotation: -360,
        repeat: -1,
      })

  }
}
</script>

